export type DuelistCategory =
  | "story"
  | "mage"
  | "highmage"
  | "boss"
  | "anime"
  | "npc"
  | "hidden"
  | "free";

export interface DuelistCategoryInfo {
  label: string;
  icon: string;
  color: string;
}

export const DUELIST_CATEGORIES: Record<DuelistCategory, DuelistCategoryInfo> = {
  story:    { label: "Story Mode",  icon: "⚔", color: "#cc2200" },
  mage:     { label: "Mage",        icon: "✦", color: "#9b30ff" },
  highmage: { label: "High Mage",   icon: "★", color: "#00d4ff" },
  boss:     { label: "Final Boss",  icon: "☠", color: "#ff0000" },
  anime:    { label: "Anime",       icon: "◈", color: "#00ff88" },
  npc:      { label: "NPC",         icon: "◉", color: "#c9a227" },
  hidden:   { label: "Hidden",      icon: "◆", color: "#cc00ff" },
  free:     { label: "Free Duel",   icon: "○", color: "#3366ff" },
};

export const DUELIST_FIELDS = [
  "Meadow", "Forest", "Mountain", "Dark", "Labyrinth",
  "Sogen", "Toon", "Yami", "Sea", "Wasteland", "None",
] as const;

export type DuelistField = (typeof DUELIST_FIELDS)[number];

export const DUELIST_SORT_OPTIONS = [
  { value: "id",        label: "ID Order" },
  { value: "name",       label: "Name A-Z" },
  { value: "diff-asc",  label: "Difficulty ↑" },
  { value: "diff-desc", label: "Difficulty ↓" },
  { value: "category",  label: "Category" },
] as const;

export interface DuelistQuote {
  text: string;
  context: string;
}

export interface DuelistDrop {
  card: string;
  pct: string;
  rarity: "common" | "rare" | "ultra";
}

export interface Duelist {
  id: number;
  name: string;
  title: string;
  category: DuelistCategory;
  difficulty: number;
  field: DuelistField;
  guardianStar: string[];
  deckType: string;
  location: string;
  description: string;
  lore: string;
  quotes: DuelistQuote[];
  signatureCards: string[];
  signatureCombo: string;
  weakness: string;
  strongCards: string[];
  deckList: string[];
  saPow: string[];
  saTec: string[];
  drops: DuelistDrop[];
  farmingTips: string[];
  image: string;
}

const NPC = (file: string) => `/images/NPC/${file}`;

